 1	import type { FC } from 'react';
 2	
 3	import type { V1beta1PlanStatusMigrationVmsPipelineTasks } from '@kubev2v/types';
 4	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	import { getTaskProgress } from '../../utils/utils';
 8	
 9	type PipelineTasksDrawerProps = {
10	  name: string;
11	  tasks: V1beta1PlanStatusMigrationVmsPipelineTasks[] | undefined;
12	};
13	
14	const PipelineTasksDrawer: FC<PipelineTasksDrawerProps> = ({ tasks }) => {
15	  const { t } = useForkliftTranslation();
16	
17	  return (
18	    <Table>
19	      <Thead>
20	        <Tr>
21	          <Th>{t('Name')}</Th>
22	          <Th>{t('Description')}</Th>
23	          <Th>{t('Progress')}</Th>
24	        </Tr>
25	      </Thead>
26	      <Tbody>
27	        {(tasks ?? []).map((task) => (
28	          <Tr key={task?.name}>
29	            <Td>{task?.name}</Td>
30	            <Td>{task?.phase}</Td>
31	            <Td>{getTaskProgress(task)}</Td>
32	          </Tr>
33	        ))}
34	      </Tbody>
35	    </Table>
36	  );
37	};
38	
39	export default PipelineTasksDrawer;

